mapper.select:
SELECT TDPD.ID, TDPD.BUSINESS_NO AS PLAN_NO, TBPE.SUB_PLAN_NO, TDPD.CARGO_OWNER_NAME AS CONSIGNOR_NAME, TDPD.PORT_NAME, TDPD.CARGO_NAME, TDPD.MASS_NAMES_TARGET_LABEL AS YARD_CODE, TDPD.END_TIME, to_char(TDPD.BEGIN_TIME,'mm-dd hh24:mi') || '~' ||to_char(TDPD.END_TIME,'mm-dd hh24:mi') PLAN_START_TIME, COUNT(T1.ID) AS SIGN_COUNT FROM T_BUS_RESERVATION_SIGN T1 LEFT JOIN T_BUS_VEHICLE_RESERVATION T2 ON T1.RESERVATION_ID = T2.ID LEFT JOIN T_BUS_PLAN_ENTRUST TBPE ON T2.SUB_PLAN_NO = TBPE.SUB_PLAN_NO LEFT JOIN T_DIS_PORT_DAYNIGHTPLAN TDPD ON TBPE.DAY_NIGHT_PLAN_ID = TDPD.ID WHERE T2.ID IS NOT NULL AND T1.STATUS IN ('1','0') and TDPD.PACKING_CODE = '2'
and T2.PLAN_NO LIKE #{planNoLike, jdbcType=VARCHAR}
and T2.CONSIGNOR_NAME LIKE #{consignorNameLike, jdbcType=VARCHAR}
and T2.VEHICLE_NO LIKE #{vehicleNoLike, jdbcType=VARCHAR}
group by TDPD.ID, TDPD.BUSINESS_NO, TBPE.SUB_PLAN_NO, TDPD.CARGO_OWNER_NAME, TDPD.PORT_NAME, TDPD.CARGO_NAME, TDPD.MASS_NAMES_TARGET_LABEL, TDPD.END_TIME, to_char(TDPD.BEGIN_TIME,'mm-dd hh24:mi') || '~' ||to_char(TDPD.END_TIME,'mm-dd hh24:mi') ORDER by TDPD.END_TIME DESC

SELECT T1.ID, T2.VEHICLE_NO, T2.DRIVER_NAME_ONE, T2.DRIVER_PHONE_ONE, T2.PLAN_NO, T2.CONSIGNOR_CODE, T2.CONSIGNOR_NAME, T2.CARGO_CODE, T2.CARGO_NAME, T2.YARD_CODE, to_char(T1.CREATE_TIME,'mm-dd hh24:mi') "signTime", T1.STATUS, DECODE(T3.NOTE_ID,null,'不在港','在港') "hasInPort" FROM T_BUS_RESERVATION_SIGN T1 LEFT JOIN T_BUS_VEHICLE_RESERVATION T2 ON T1.RESERVATION_ID = T2.ID LEFT JOIN WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND T3 ON T2.DRIVER_NO_ONE = T3.ID_NUMBER AND T3.IS_FINISHED = 0 AND T3.IS_DELETE = 0 WHERE T2.ID IS NOT NULL AND T1.STATUS IN ('1','0')
and T2.SUB_PLAN_NO = #{subPlanNo}
ORDER by T1.CREATE_TIME
